// Validar secret y mapear campos a OKX
const expected = $env.WEBHOOK_SECRET || 'changeme';
const p = items[0].json;
if (!p.secret || String(p.secret) !== String(expected)) {
  throw new Error('Invalid secret');
}
function mapInstId(symbol) {
  symbol = String(symbol).toUpperCase();
  if (symbol.includes('-USDT-')) return symbol;
  if (symbol.endsWith('-USDT')) return symbol + '-SWAP';
  if (symbol.endsWith('USDT')) return symbol.slice(0, -4) + '-USDT-SWAP';
  return symbol + '-USDT-SWAP';
}
const out = {
  instId: mapInstId(p.symbol),
  side: (p.side || 'buy').toLowerCase(),
  ordType: (p.type || 'market').toLowerCase(),
  sz: String(p.size || '1'),
  tdMode: p.tdMode || 'isolated',
  lever: p.lever || '5',
  posSide: p.posSide || undefined,
  px: (p.price && p.type === 'limit') ? String(p.price) : undefined,
  clOrdId: p.clOrdId || undefined,
  reduceOnly: p.reduceOnly ? 'true' : undefined,
};
return [{ json: out }];

// Firma OKX y añade headers
const crypto = require('crypto');
const baseUrl = $env.OKX_BASE_URL || 'https://www.okx.com';
const apiKey = $env.OKX_API_KEY;
const secretKey = $env.OKX_SECRET_KEY;
const passphrase = $env.OKX_PASSPHRASE;
const simulated = ($env.OKX_SIMULATED || '1') === '1';
if (!apiKey || !secretKey || !passphrase) {
  throw new Error('Faltan credenciales OKX en variables de entorno');
}
const path = '/api/v5/trade/order';
const ts = new Date().toISOString().replace(/\..+/, '.000Z');
const body = JSON.stringify(items[0].json);
const preSign = ts + 'POST' + path + body;
const sign = crypto.createHmac('sha256', secretKey).update(preSign).digest('base64');
const headers = {
  'OK-ACCESS-KEY': apiKey,
  'OK-ACCESS-SIGN': sign,
  'OK-ACCESS-TIMESTAMP': ts,
  'OK-ACCESS-PASSPHRASE': passphrase,
  'Content-Type': 'application/json',
};
if (simulated) headers['x-simulated-trading'] = '1';
return [{
  json: { url: baseUrl + path, body: JSON.parse(body) },
  headers
}];
